### 10. Provider Setup (Prodia Example)

Shows how to structure a provider with image support:

**File: /private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775397849627-f3boyg/packages/prodia/src/prodia-provider.ts**

```typescript
export interface ProdiaProvider extends ProviderV3 {
  languageModel(modelId: ProdiaLanguageModelId): LanguageModelV3;
  image(modelId: ProdiaImageModelId): ImageModelV3;
  imageModel(modelId: ProdiaImageModelId): ImageModelV3;
  video(modelId: ProdiaVideoModelId): Experimental_VideoModelV3;
  videoModel(modelId: ProdiaVideoModelId): Experimental_VideoModelV3;
}

export function createProdia(options: ProdiaProviderSettings = {}): ProdiaProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PRODIA_TOKEN',
          description: 'Prodia',
        })}`,
        ...options.headers,
      },
      `ai-sdk/prodia/${VERSION}`,
    );

  const createImageModel = (modelId: ProdiaImageModelId) =>
    new ProdiaImageModel(modelId, {
      provider: 'prodia.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3',
    image: createImageModel,
    imageModel: createImageModel,
    // ... other model types
  };
}

export const prodia = createProdia();
```

