/**
 * PixelArt image model IDs.
 */
export type PixelArtImageModelId =
  | 'pixelart-standard'
  | 'pixelart-hd'
  | (string & {});

/**
 * PixelArt image generation settings.
 */
export interface PixelArtImageSettings {
  /**
   * The size of the generated images.
   * Must have the format `{width}x{height}` (e.g., `"256x256"`, `"512x512"`).
   */
  size?: string;

  /**
   * The visual style of the generated pixel art.
   *
   * - `pixel`: Standard pixel art style
