import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, Schema } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  lazySchema,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';
import { pixelartFailedResponseHandler } from './pixelart-error';

export interface PixelArtImageModelConfig {
  provider: string;
  url: (options: { path: string; modelId: string }) => string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

interface PixelArtImageResponse {
  data: Array<{ b64_json: string }>;
  created?: number | null;
}

const pixelartImageResponseSchema = lazySchema(
  () =>
    zodSchema(
      z.object({
        data: z.array(
          z.object({
            b64_json: z.string(),
          }),
        ),
        created: z.number().nullish(),
      }),
    ) as Schema<PixelArtImageResponse>,
);

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    const resolvedSize = size ?? this.settings.size;
    const resolvedStyle = this.settings.style;
    const resolvedPixelDensity = this.settings.pixelDensity;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({
        path: '/images/generations',
        modelId: this.modelId,
      }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(resolvedSize != null ? { size: resolvedSize } : {}),
        ...(resolvedStyle != null ? { style: resolvedStyle } : {}),
        ...(resolvedPixelDensity != null
          ? { pixel_density: resolvedPixelDensity }
          : {}),
        response_format: 'b64_json',
        ...(providerOptions.pixelart ?? {}),
      },
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.data.map(() => ({
            created: response.created ?? undefined,
          })),
        },
      },
    };
  }
}

